/*
 * CNC Motor Controller Registers
 *
 * Register map for 3-axis CNC milling machine motor controller
 * with spindle control and encoder feedback.
 *
 * Features:
 * - 3 servo motors (X, Y, Z axes) with encoder feedback
 * - 1 high-speed spindle motor
 * - Critically damped PID motion control
 * - Jog functionality
 * - State machine control
 */

/***** read only registers *****/

// Standard datastream registers
uint32_t    DS_PACKET_COUNT;
uint32_t    DS_ERROR_COUNT;
uint32_t    CONTROL_INTERFACE;
uint32_t    COUNTER_1HZ;

// Controller state (0=IDLE, 1=HOMING, 2=READY, 3=RUNNING, 4=PAUSED, 5=ERROR, 6=E_STOP)
uint32_t    CONTROLLER_STATE;

// Motor encoder readings (encoder counts, int32_t)
int         MOTOR_X_ENCODER;
int         MOTOR_Y_ENCODER;
int         MOTOR_Z_ENCODER;

// Spindle status
uint32_t    SPINDLE_RPM;        // Current spindle speed in RPM
uint32_t    SPINDLE_LOAD;       // Spindle load percentage (0-100)

// Motor enable status (0=disabled, 1=enabled)
uint32_t    MOTOR_X_ENABLED;
uint32_t    MOTOR_Y_ENABLED;
uint32_t    MOTOR_Z_ENABLED;
uint32_t    SPINDLE_ENABLED;

read/write

// Motor position setpoints (encoder counts, int32_t)
int         MOTOR_X_SETPOINT;
int         MOTOR_Y_SETPOINT;
int         MOTOR_Z_SETPOINT;

// Spindle speed setpoint
uint32_t    SPINDLE_SPEED_SETPOINT;     // Target RPM

// Jog distance (encoder counts per jog step)
int         JOG_DISTANCE;
